+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "asana.workspaces.list" => "asana.workspaces.read",
+        "asana.projects.list" | "asana.projects.get" => "asana.projects.read",
+        "asana.tasks.list" | "asana.tasks.get" | "asana.tasks.search" => "asana.tasks.read",
+        "asana.tasks.create" | "asana.tasks.update" | "asana.tasks.delete" => "asana.tasks.write",
+        "asana.sections.list" => "asana.sections.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+
+    capability
+        .parse::<CapabilityId>()
+        .map_err(|err| FcpError::Internal {
+            message: format!("invalid capability id mapping for {operation}: {err}"),
