+impl BoxConnectorAdapter {
+    fn new() -> Self {
+        Self {
+            connector: BoxConnector::new(),
+            id: ConnectorId::from_static("box"),
+            instance_id: InstanceId::new(),
+            verifier: None,
+            introspection: Introspection {
+                operations: vec![],
