+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "box.files.get" => "box.files.read",
+        "box.files.upload" | "box.files.delete" => "box.files.write",
+        "box.folders.list" => "box.folders.read",
+        "box.sharing.list" => "box.sharing.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+
+    capability
+        .parse::<CapabilityId>()
+        .map_err(|err| FcpError::Internal {
+            message: format!("invalid capability id mapping for {operation}: {err}"),
+        })
