+
+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "datadog.events.create" => "datadog.events.write",
+        "datadog.events.list" => "datadog.events.read",
+        "datadog.logs.search" => "datadog.logs.read",
+        "datadog.metrics.query" => "datadog.metrics.read",
+        "datadog.metrics.submit" => "datadog.metrics.write",
+        "datadog.monitors.create" => "datadog.monitors.write",
+        "datadog.monitors.delete" => "datadog.monitors.write",
+        "datadog.monitors.list" => "datadog.monitors.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+
+    capability
+        .parse::<CapabilityId>()
+        .map_err(|err| FcpError::Internal {
+            message: format!("invalid capability id mapping for {operation}: {err}"),
+        })
+}
