+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "elasticsearch.search" | "elasticsearch.get_document" => "elasticsearch.search.read",
+        "elasticsearch.index_document" | "elasticsearch.bulk" => "elasticsearch.index.write",
+        "elasticsearch.indices.list" => "elasticsearch.indices.read",
+        "elasticsearch.indices.delete" => "elasticsearch.indices.write",
+        "elasticsearch.cluster.health" => "elasticsearch.cluster.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+    capability.parse::<CapabilityId>().map_err(|err| FcpError::Internal {
+        message: format!("invalid capability id mapping for {operation}: {err}"),
+    })
