+//! E2E GitLab connector compliance tests.
+//!
+//! Exercises the GitLab connector through the shared E2E harness:
+//! - Default deny behavior for capability mismatch
+//! - Allow path with valid capability token
+//! - Network guard allow/deny checks via manifest constraints
+//!
+//! All tests are deterministic with mock servers only.
+//! Run: `cargo test --package fcp-e2e --features gitlab`
+
+#![cfg(feature = "gitlab")]
+#![allow(clippy::too_many_lines)]
+
+use chrono::{Duration as ChronoDuration, Utc};
+use fcp_conformance::DynamicSuite;
+use fcp_core::{
+    CapabilityGrant, CapabilityId, CapabilityToken, CapabilityVerifier, ConnectorId,
+    ConnectorMetrics, FcpConnector, FcpError, HandshakeRequest, HandshakeResponse, HealthSnapshot,
+    InstanceId, Introspection, InvokeRequest, InvokeResponse, OperationId, RequestId, SessionId,
+    ShutdownRequest, SimulateRequest, SimulateResponse, SubscribeRequest, SubscribeResponse,
+    UnsubscribeRequest, ZoneId,
+};
+use fcp_crypto::{cose::CapabilityTokenBuilder, ed25519::Ed25519SigningKey};
+use fcp_e2e::{ComplianceSuite, E2eRunner};
+use fcp_gitlab::connector::GitLabConnector;
+use fcp_manifest::ConnectorManifest;
+use fcp_testkit::MockApiServer;
+use serde_json::json;
+
+struct GitLabConnectorAdapter {
+    connector: GitLabConnector,
+    id: ConnectorId,
+    instance_id: InstanceId,
+    verifier: Option<CapabilityVerifier>,
+    introspection: Introspection,
+}
+
+impl GitLabConnectorAdapter {
+    fn new() -> Self {
+        Self {
+            connector: GitLabConnector::new(),
+            id: ConnectorId::from_static("gitlab"),
+            instance_id: InstanceId::new(),
+            verifier: None,
+            introspection: Introspection {
+                operations: vec![],
+                events: vec![],
+                resource_types: vec![],
+                auth_caps: None,
+                event_caps: None,
+            },
+        }
+    }
+}
+
+#[fcp_core::async_trait]
+impl FcpConnector for GitLabConnectorAdapter {
+    fn id(&self) -> &ConnectorId {
+        &self.id
+    }
+
+    async fn configure(&mut self, config: serde_json::Value) -> fcp_core::FcpResult<()> {
+        self.connector.handle_configure(config).await.map(|_| ())
+    }
+
+    async fn handshake(&mut self, req: HandshakeRequest) -> fcp_core::FcpResult<HandshakeResponse> {
+        self.connector
+            .handle_handshake(json!({ "session_id": "gitlab-e2e-session" }))
+            .await?;
+
+        self.verifier = Some(CapabilityVerifier::new(
+            req.host_public_key,
+            req.zone.clone(),
+            self.instance_id.clone(),
+        ));
+
+        Ok(HandshakeResponse {
+            status: "accepted".to_string(),
+            capabilities_granted: req
+                .capabilities_requested
+                .iter()
+                .cloned()
+                .map(|capability| CapabilityGrant { capability, operation: None })
+                .collect(),
+            session_id: SessionId::new(),
+            manifest_hash: "sha256:gitlab-e2e".to_string(),
+            nonce: req.nonce,
+            event_caps: None,
+            auth_caps: None,
+            op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        match self.connector.handle_health().await {
+            Ok(payload) => {
+                let status = payload.get("status").and_then(serde_json::Value::as_str).unwrap_or("unknown");
+                match status {
+                    "healthy" => HealthSnapshot::ready(),
+                    "degraded" => HealthSnapshot::degraded("not_handshaken"),
+                    "unconfigured" => HealthSnapshot::degraded("not_configured"),
+                    other => HealthSnapshot::degraded(format!("gitlab_status:{other}")),
+                }
+            }
+            Err(err) => HealthSnapshot::error(err.to_string()),
+        }
+    }
+
+    async fn self_check(&self) -> fcp_core::FcpResult<fcp_core::SelfCheckReport> {
+        let value = self.connector.handle_self_check().await?;
+        serde_json::from_value(value).map_err(|err| FcpError::Internal {
+            message: format!("failed to deserialize GitLab self_check: {err}"),
+        })
+    }
+
+    fn metrics(&self) -> ConnectorMetrics { ConnectorMetrics::default() }
+
+    async fn shutdown(&mut self, _req: ShutdownRequest) -> fcp_core::FcpResult<()> {
+        self.verifier = None;
+        self.connector.handle_shutdown(json!({})).await.map(|_| ())
+    }
+
+    fn introspect(&self) -> Introspection { self.introspection.clone() }
+
+    async fn invoke(&self, req: InvokeRequest) -> fcp_core::FcpResult<InvokeResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal {
+            message: "GitLab verifier not initialized; handshake required".into(),
+        })?;
+        let required_capability = required_capability(req.operation.as_str())?;
+        verifier.verify(&req.capability_token, &required_capability, &req.operation, &[])?;
+
+        let request_id = req.id.clone();
+        let value = self.connector.handle_invoke(json!({
+            "operation_id": req.operation.as_str(),
+            "input": req.input,
+        })).await?;
+        Ok(InvokeResponse::ok(request_id, value))
+    }
+
+    async fn simulate(&self, req: SimulateRequest) -> fcp_core::FcpResult<SimulateResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal {
+            message: "GitLab verifier not initialized; handshake required".into(),
+        })?;
+        let required_capability = required_capability(req.operation.as_str())?;
+        verifier.verify(&req.capability_token, &required_capability, &req.operation, &[])?;
+
+        let value = self.connector.handle_simulate(json!({
+            "operation_id": req.operation.as_str(),
+            "input": req.input,
+        })).await?;
+
+        Ok(SimulateResponse {
+            r#type: "simulate_response".to_string(),
+            id: req.id,
+            would_succeed: value.get("allowed").and_then(serde_json::Value::as_bool).unwrap_or(false),
+            failure_reason: value.get("reason").and_then(serde_json::Value::as_str)
+                .filter(|_| !value.get("allowed").and_then(serde_json::Value::as_bool).unwrap_or(false))
+                .map(str::to_string),
+            denial_code: None,
+            missing_capabilities: Vec::new(),
+            estimated_cost: None,
+            availability: None,
+            response_metadata: None,
+        })
+    }
+
+    async fn subscribe(&self, _req: SubscribeRequest) -> fcp_core::FcpResult<SubscribeResponse> {
+        Err(FcpError::StreamingNotSupported)
+    }
+
+    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> fcp_core::FcpResult<()> { Ok(()) }
+}
+
+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "gitlab.projects.list" => "gitlab.projects.read",
+        "gitlab.issues.list" => "gitlab.issues.read",
+        "gitlab.issues.create" => "gitlab.issues.write",
+        "gitlab.merge_requests.list" => "gitlab.merge_requests.read",
+        "gitlab.pipelines.list" => "gitlab.pipelines.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+    capability.parse::<CapabilityId>().map_err(|err| FcpError::Internal {
+        message: format!("invalid capability id mapping for {operation}: {err}"),
+    })
+}
+
+fn gitlab_manifest_with_hash() -> String {
+    let raw = include_str!("../../../connectors/gitlab/manifest.toml");
+    let unchecked = ConnectorManifest::parse_str_unchecked(raw).expect("unchecked manifest parse");
+    let computed = unchecked.compute_interface_hash().expect("compute interface hash");
+    raw.replace(&unchecked.manifest.interface_hash.to_string(), &computed.to_string())
+}
+
+fn gitlab_manifest_toml() -> toml::Value {
+    toml::from_str(include_str!("../../../connectors/gitlab/manifest.toml"))
+        .expect("GitLab manifest TOML")
+}
+
+fn gitlab_config(base_url: &str) -> serde_json::Value {
+    json!({ "private_token": "gitlab-test-private-token", "base_url": base_url })
+}
+
+fn handshake_request(host_public_key: [u8; 32], capabilities: &[&str]) -> HandshakeRequest {
+    HandshakeRequest {
+        protocol_version: "2.0".to_string(),
+        zone: ZoneId::work(),
+        zone_dir: None,
+        host_public_key,
+        nonce: [19_u8; 32],
+        capabilities_requested: capabilities
+            .iter()
+            .map(|c| c.parse::<CapabilityId>().expect("capability id parse"))
+            .collect(),
+        host: None,
+        transport_caps: None,
+        requested_instance_id: Some(InstanceId::new()),
+    }
+}
+
+fn build_token(signing_key: &Ed25519SigningKey, capability: &str, operations: &[&str]) -> CapabilityToken {
+    let now = Utc::now();
+    let token = CapabilityTokenBuilder::new()
+        .capability_id(capability)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(operations)
+        .issuer("node:test")
+        .validity(now, now + ChronoDuration::hours(1))
+        .sign(signing_key)
+        .expect("capability token sign");
+    CapabilityToken { raw: token }
+}
+
+fn invoke_request(operation: &'static str, input: serde_json::Value, token: CapabilityToken) -> InvokeRequest {
+    InvokeRequest {
+        r#type: "invoke".to_string(),
+        id: RequestId::from("gitlab-e2e"),
+        connector_id: ConnectorId::from_static("gitlab"),
+        operation: OperationId::from_static(operation),
+        zone_id: ZoneId::work(),
+        input,
+        capability_token: token,
+        holder_proof: None, context: None, idempotency_key: None, lease_seq: None,
+        deadline_ms: None, correlation_id: None, provenance: None, approval_tokens: Vec::new(),
+    }
+}
+
+fn operation_network_constraints<'a>(manifest: &'a toml::Value, operation_name: &str) -> &'a toml::value::Table {
+    manifest.get("provides").and_then(toml::Value::as_table)
+        .and_then(|p| p.get("operations")).and_then(toml::Value::as_table)
+        .and_then(|o| o.get(operation_name)).and_then(toml::Value::as_table)
+        .and_then(|op| op.get("network_constraints")).and_then(toml::Value::as_table)
+        .expect("operation network_constraints")
+}
+
+fn operation_host_allow_list(manifest: &toml::Value, operation_name: &str) -> Vec<String> {
+    operation_network_constraints(manifest, operation_name)
+        .get("host_allow").and_then(toml::Value::as_array)
+        .map(|hosts| hosts.iter().filter_map(toml::Value::as_str).map(str::to_string).collect())
+        .expect("operation host_allow")
+}
+
+fn host_allowed(host: &str, host_allow: &[String]) -> bool {
+    host_allow.iter().any(|pattern| {
+        pattern == host
+            || pattern.strip_prefix("*.").is_some_and(|suffix| host.ends_with(&format!(".{suffix}")))
+    })
+}
+
+#[fcp_async_core::runtime::test]
+async fn gitlab_default_deny_compliance_suite_passes() {
+    let mock = MockApiServer::start().await;
