+        "grafana.dashboards.create" | "grafana.dashboards.delete" => "grafana.dashboards.write",
+        "grafana.datasources.list" | "grafana.datasources.query" => "grafana.datasources.read",
+        "grafana.alerts.list" => "grafana.alerts.read",
+        "grafana.alerts.create" => "grafana.alerts.write",
+        "grafana.annotations.create" => "grafana.annotations.write",
+        _ => {
