+    async fn handshake(&mut self, req: HandshakeRequest) -> fcp_core::FcpResult<HandshakeResponse> {
+        // Call the raw connector handshake to set internal state (session_id, handshaken flag).
+        let session_id = SessionId::new();
+        self.connector
+            .handle_handshake(json!({
+                "session_id": session_id.to_string(),
+            }))
+            .await?;
+
+        // Build a proper HandshakeResponse expected by the E2E harness.
+        let capabilities_granted: Vec<CapabilityGrant> = req
+            .capabilities_requested
+            .into_iter()
+            .map(|cap| CapabilityGrant {
+                capability: cap,
+                operation: None,
+            })
+            .collect();
+
+        Ok(HandshakeResponse {
+            status: "accepted".into(),
+            capabilities_granted,
+            session_id,
+            manifest_hash: "sha256:homeassistant-connector-v1".into(),
+            nonce: req.nonce,
+            event_caps: None,
+            auth_caps: None,
+            op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        match self.connector.handle_health().await {
+            Ok(payload) => {
+                let status = payload
+                    .get("status")
+                    .and_then(serde_json::Value::as_str)
+                    .unwrap_or("unknown");
+                match status {
+                    "healthy" => HealthSnapshot::ready(),
+                    "not_configured" | "unconfigured" => {
+                        HealthSnapshot::degraded("not_configured")
+                    }
+                    other => {
+                        HealthSnapshot::degraded(format!("homeassistant_status:{other}"))
+                    }
+                }
+            }
+            Err(err) => HealthSnapshot::error(err.to_string()),
