+    let invoke = invoke_request(
+        "hubspot.contacts.list",
+        json!({ "limit": 10 }),
+        token,
+    );
+    let suite = ConnectorSuite {
+        test_name: "hubspot_allow_valid_token".to_string(),
+        config: json!({
