+                .and_then(toml::Value::as_bool),
+            Some(false),
+            "operation {operation_name} must allow private ranges (self-hosted)"
+        );
+        assert_eq!(
+            constraints
+                .get("require_sni")
+                .and_then(toml::Value::as_bool),
+            Some(false),
+            "operation {operation_name} does not require SNI (self-hosted HTTP possible)"
+        );
+    }
