+    id: ConnectorId,
+    instance_id: InstanceId,
+    verifier: Option<CapabilityVerifier>,
+    introspection: Introspection,
+}
+
+impl MixpanelConnectorAdapter {
+    fn new() -> Self {
+        Self {
+            connector: MixpanelConnector::new(),
+            id: ConnectorId::from_static("mixpanel"),
+            instance_id: InstanceId::new(),
+            verifier: None,
+            introspection: Introspection {
+                operations: vec![],
+                events: vec![],
+                resource_types: vec![],
+                auth_caps: None,
+                event_caps: None,
+            },
+        }
+    }
+}
