+#[fcp_core::async_trait]
+impl FcpConnector for MixpanelConnectorAdapter {
+    fn id(&self) -> &ConnectorId { &self.id }
+
+    async fn configure(&mut self, config: serde_json::Value) -> fcp_core::FcpResult<()> {
+        self.connector.handle_configure(config).await.map(|_| ())
+    }
+
+    async fn handshake(&mut self, req: HandshakeRequest) -> fcp_core::FcpResult<HandshakeResponse> {
+        self.connector.handle_handshake(json!({"session_id": "mixpanel-e2e-session"})).await?;
+        self.verifier = Some(CapabilityVerifier::new(req.host_public_key, req.zone.clone(), self.instance_id.clone()));
+        Ok(HandshakeResponse {
+            status: "accepted".to_string(),
+            capabilities_granted: req.capabilities_requested.iter().cloned().map(|capability| CapabilityGrant { capability, operation: None }).collect(),
+            session_id: SessionId::new(),
+            manifest_hash: "sha256:mixpanel-e2e".to_string(),
+            nonce: req.nonce,
+            event_caps: None, auth_caps: None, op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        match self.connector.handle_health().await {
+            Ok(payload) => {
+                let status = payload.get("status").and_then(serde_json::Value::as_str).unwrap_or("unknown");
+                match status {
+                    "healthy" => HealthSnapshot::ready(),
+                    "degraded" => HealthSnapshot::degraded("not_handshaken"),
+                    "unconfigured" => HealthSnapshot::degraded("not_configured"),
+                    other => HealthSnapshot::degraded(format!("mixpanel_status:{other}")),
+                }
+            }
+            Err(err) => HealthSnapshot::error(err.to_string()),
+        }
+    }
+
+    async fn self_check(&self) -> fcp_core::FcpResult<fcp_core::SelfCheckReport> {
+        let value = self.connector.handle_self_check().await?;
+        serde_json::from_value(value).map_err(|err| FcpError::Internal { message: format!("failed to deserialize Mixpanel self_check: {err}") })
+    }
+
+    fn metrics(&self) -> ConnectorMetrics { ConnectorMetrics::default() }
+
+    async fn shutdown(&mut self, _req: ShutdownRequest) -> fcp_core::FcpResult<()> {
+        self.verifier = None;
+        self.connector.handle_shutdown(json!({})).await.map(|_| ())
+    }
+
+    fn introspect(&self) -> Introspection { self.introspection.clone() }
+
+    async fn invoke(&self, req: InvokeRequest) -> fcp_core::FcpResult<InvokeResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal { message: "Mixpanel verifier not initialized; handshake required".into() })?;
+        let cap = required_capability(req.operation.as_str())?;
+        verifier.verify(&req.capability_token, &cap, &req.operation, &[])?;
+        let request_id = req.id.clone();
+        let value = self.connector.handle_invoke(json!({"operation_id": req.operation.as_str(), "input": req.input})).await?;
+        Ok(InvokeResponse::ok(request_id, value))
+    }
+
+    async fn simulate(&self, req: SimulateRequest) -> fcp_core::FcpResult<SimulateResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal { message: "Mixpanel verifier not initialized; handshake required".into() })?;
+        let cap = required_capability(req.operation.as_str())?;
+        verifier.verify(&req.capability_token, &cap, &req.operation, &[])?;
+        let value = self.connector.handle_simulate(json!({"operation_id": req.operation.as_str(), "input": req.input})).await?;
+        Ok(SimulateResponse {
+            r#type: "simulate_response".to_string(), id: req.id,
+            would_succeed: value.get("allowed").and_then(serde_json::Value::as_bool).unwrap_or(false),
+            failure_reason: value.get("reason").and_then(serde_json::Value::as_str).filter(|_| !value.get("allowed").and_then(serde_json::Value::as_bool).unwrap_or(false)).map(str::to_string),
+            denial_code: None, missing_capabilities: Vec::new(), estimated_cost: None, availability: None, response_metadata: None,
+        })
+    }
+
+    async fn subscribe(&self, _req: SubscribeRequest) -> fcp_core::FcpResult<SubscribeResponse> { Err(FcpError::StreamingNotSupported) }
+    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> fcp_core::FcpResult<()> { Ok(()) }
+}
+
+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "mixpanel.events.query" => "mixpanel.events.read",
+        "mixpanel.funnels.list" => "mixpanel.funnels.read",
+        "mixpanel.insights.query" => "mixpanel.insights.read",
+        _ => { return Err(FcpError::InvalidRequest { code: 1002, message: format!("Unknown operation: {operation}") }); }
+    };
+    capability.parse::<CapabilityId>().map_err(|err| FcpError::Internal { message: format!("invalid capability id mapping for {operation}: {err}") })
+}
