+    CapabilityToken { raw: token }
+}
+
+fn invoke_request(operation: &'static str, input: serde_json::Value, token: CapabilityToken) -> InvokeRequest {
+    InvokeRequest {
+        r#type: "invoke".to_string(), id: RequestId::from("mixpanel-e2e"),
+        connector_id: ConnectorId::from_static("mixpanel"), operation: OperationId::from_static(operation),
+        zone_id: ZoneId::work(), input, capability_token: token,
+        holder_proof: None, context: None, idempotency_key: None, lease_seq: None,
