+    let token = CapabilityTokenBuilder::new()
+        .capability_id(capability)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(operations)
+        .issuer("node:test")
+        .validity(now, now + ChronoDuration::hours(1))
+        .sign(signing_key)
+        .expect("capability token sign");
+    CapabilityToken { raw: token }
+}
