+//! E2E Reddit connector compliance tests.
+//!
+//! Exercises the Reddit connector through the E2E compliance harness:
+//! - Default deny (missing capability -> error + decision receipt)
+//! - Allow with valid token (happy path invoke via mock REST API)
+//! - Network guard allow/deny (manifest `host_allow` wildcard validation)
+//!
+//! All tests are deterministic -- no real API calls.
+//! Run: `cargo test --package fcp-e2e --features reddit`
+
+#![cfg(feature = "reddit")]
+#![allow(clippy::too_many_lines)]
+
+use chrono::{Duration as ChronoDuration, Utc};
+use fcp_conformance::DynamicSuite;
+use fcp_core::{
+    AgentHint, CapabilityGrant, CapabilityId, CapabilityToken, ConnectorId, ConnectorMetrics,
+    FcpConnector, FcpError, HandshakeRequest, HandshakeResponse, HealthSnapshot,
+    IdempotencyClass, InstanceId, Introspection, InvokeRequest, InvokeResponse, InvokeStatus,
+    OperationId, OperationInfo, RequestId, RiskLevel, SafetyTier, SessionId, ShutdownRequest,
+    SimulateRequest, SimulateResponse, SubscribeRequest, SubscribeResponse, UnsubscribeRequest,
+    ZoneId,
+};
+use fcp_crypto::{cose::CapabilityTokenBuilder, ed25519::Ed25519SigningKey};
+use fcp_e2e::{ComplianceSuite, ConnectorSuite, E2eRunner, InvokeExpectations};
+use fcp_manifest::ConnectorManifest;
+use fcp_testkit::MockApiServer;
+use serde_json::json;
+use wiremock::{
+    Mock, ResponseTemplate,
+    matchers::{method, path_regex},
+};
+
+use fcp_reddit::connector::RedditConnector;
+
+// ============================================================================
+// FcpConnector adapter for RedditConnector
+// ============================================================================
+
+struct RedditConnectorAdapter {
+    connector: RedditConnector,
+    id: ConnectorId,
+}
+
+impl RedditConnectorAdapter {
+    fn new() -> Self {
+        Self {
+            connector: RedditConnector::new(),
+            id: ConnectorId::from_static("reddit"),
+        }
+    }
+}
+
+#[fcp_core::async_trait]
+impl FcpConnector for RedditConnectorAdapter {
+    fn id(&self) -> &ConnectorId {
+        &self.id
+    }
+
+    async fn configure(&mut self, config: serde_json::Value) -> fcp_core::FcpResult<()> {
+        self.connector.handle_configure(config).await.map(|_| ())
+    }
+
+    async fn handshake(&mut self, req: HandshakeRequest) -> fcp_core::FcpResult<HandshakeResponse> {
+        let session_id = SessionId::new();
+        self.connector
+            .handle_handshake(json!({
+                "session_id": session_id.to_string(),
+            }))
+            .await?;
+
+        let capabilities_granted: Vec<CapabilityGrant> = req
+            .capabilities_requested
+            .into_iter()
+            .map(|cap| CapabilityGrant {
+                capability: cap,
+                operation: None,
+            })
+            .collect();
+
+        Ok(HandshakeResponse {
+            status: "accepted".into(),
+            capabilities_granted,
+            session_id,
+            manifest_hash: "sha256:reddit-connector-v1".into(),
+            nonce: req.nonce,
+            event_caps: None,
+            auth_caps: None,
+            op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        match self.connector.handle_health().await {
+            Ok(payload) => {
+                let status = payload
+                    .get("status")
+                    .and_then(serde_json::Value::as_str)
+                    .unwrap_or("unknown");
+                match status {
+                    "healthy" => HealthSnapshot::ready(),
+                    "not_configured" | "unconfigured" => {
+                        HealthSnapshot::degraded("not_configured")
+                    }
+                    other => HealthSnapshot::degraded(format!("reddit_status:{other}")),
+                }
+            }
+            Err(err) => HealthSnapshot::error(err.to_string()),
+        }
+    }
+
+    fn metrics(&self) -> ConnectorMetrics {
+        ConnectorMetrics::default()
+    }
+
+    async fn shutdown(&mut self, _req: ShutdownRequest) -> fcp_core::FcpResult<()> {
+        self.connector.handle_shutdown(json!({})).await.map(|_| ())
+    }
+
+    fn introspect(&self) -> Introspection {
+        Introspection {
+            operations: vec![OperationInfo {
+                id: OperationId::from_static("reddit.list_subreddit_new"),
+                summary: "List newest posts from a subreddit".to_string(),
+                description: None,
+                input_schema: json!({
+                    "type": "object",
+                    "required": ["subreddit"],
+                    "properties": {
+                        "subreddit": { "type": "string" },
+                        "limit": { "type": "integer" }
+                    }
+                }),
+                output_schema: json!({
+                    "type": "object",
+                    "properties": {
+                        "posts": { "type": "array" }
+                    }
+                }),
+                capability: CapabilityId::from_static("reddit.read"),
+                risk_level: RiskLevel::Low,
+                safety_tier: SafetyTier::Safe,
+                idempotency: IdempotencyClass::Strict,
+                ai_hints: AgentHint {
+                    when_to_use: "List newest posts from a subreddit.".to_string(),
+                    common_mistakes: Vec::new(),
+                    examples: vec![r#"{"subreddit": "machinelearning", "limit": 25}"#.to_string()],
+                    related: Vec::new(),
+                },
+                rate_limit: None,
+                requires_approval: None,
+            }],
+            events: Vec::new(),
+            resource_types: Vec::new(),
+            auth_caps: None,
+            event_caps: None,
+        }
+    }
+
+    async fn invoke(&self, req: InvokeRequest) -> fcp_core::FcpResult<InvokeResponse> {
+        let request_id = req.id;
+        let params = json!({
+            "operation_id": req.operation.as_str(),
+            "input": req.input,
+            "capability_token": req.capability_token,
+        });
+        let value = self.connector.handle_invoke(params).await?;
+        Ok(InvokeResponse::ok(request_id, value))
+    }
+
+    async fn simulate(&self, req: SimulateRequest) -> fcp_core::FcpResult<SimulateResponse> {
+        let request = serde_json::to_value(req).map_err(|err| FcpError::Internal {
+            message: format!("failed to serialize simulate request: {err}"),
+        })?;
+        let value = self.connector.handle_simulate(request).await?;
+        serde_json::from_value(value).map_err(|err| FcpError::Internal {
+            message: format!("failed to deserialize simulate response: {err}"),
+        })
+    }
+
+    async fn subscribe(&self, _req: SubscribeRequest) -> fcp_core::FcpResult<SubscribeResponse> {
+        Err(FcpError::StreamingNotSupported)
+    }
+
+    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> fcp_core::FcpResult<()> {
+        Ok(())
+    }
+}
+
+// ============================================================================
+// Helpers
+// ============================================================================
+
+fn reference_manifest_with_hash() -> String {
+    let raw = include_str!("../../../tests/vectors/manifest/manifest_valid.toml");
+    let unchecked = ConnectorManifest::parse_str_unchecked(raw).expect("unchecked manifest parse");
+    let computed = unchecked
+        .compute_interface_hash()
+        .expect("compute interface hash");
+    raw.replace(
+        &unchecked.manifest.interface_hash.to_string(),
+        &computed.to_string(),
+    )
+}
+
+fn handshake_request(host_public_key: [u8; 32], capabilities: &[&str]) -> HandshakeRequest {
+    HandshakeRequest {
+        protocol_version: "2.0".to_string(),
+        zone: ZoneId::work(),
+        zone_dir: None,
+        host_public_key,
+        nonce: [7u8; 32],
+        capabilities_requested: capabilities
+            .iter()
+            .map(|cap| cap.parse::<CapabilityId>().expect("capability id parse"))
+            .collect(),
+        host: None,
+        transport_caps: None,
+        requested_instance_id: Some(InstanceId::new()),
+    }
+}
+
+fn build_token(
+    signing_key: &Ed25519SigningKey,
+    capability: &str,
+    operations: &[&str],
+) -> CapabilityToken {
+    let now = Utc::now();
+    let cose = CapabilityTokenBuilder::new()
+        .capability_id(capability)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(operations)
+        .issuer("node:test")
+        .validity(now, now + ChronoDuration::hours(1))
+        .sign(signing_key)
+        .expect("capability token sign");
+    CapabilityToken { raw: cose }
+}
+
+fn invoke_request(
+    operation: &'static str,
+    input: serde_json::Value,
+    token: CapabilityToken,
+) -> InvokeRequest {
+    InvokeRequest {
+        r#type: "invoke".to_string(),
+        id: RequestId::from("reddit-e2e"),
+        connector_id: ConnectorId::from_static("reddit"),
+        operation: OperationId::from_static(operation),
+        zone_id: ZoneId::work(),
+        input,
+        capability_token: token,
+        holder_proof: None,
+        context: None,
+        idempotency_key: None,
+        lease_seq: None,
+        deadline_ms: None,
+        correlation_id: None,
+        provenance: None,
+        approval_tokens: Vec::new(),
+    }
+}
+
+fn reddit_manifest_toml() -> toml::Value {
+    toml::from_str(include_str!("../../../connectors/reddit/manifest.toml"))
+        .expect("reddit manifest toml")
+}
+
+fn operation_host_allow_list(manifest: &toml::Value, operation_name: &str) -> Vec<String> {
+    manifest
+        .get("provides")
+        .and_then(toml::Value::as_table)
+        .and_then(|provides| provides.get("operations"))
+        .and_then(toml::Value::as_table)
+        .and_then(|operations| operations.get(operation_name))
+        .and_then(toml::Value::as_table)
+        .and_then(|operation| operation.get("network_constraints"))
+        .and_then(toml::Value::as_table)
+        .and_then(|constraints| constraints.get("host_allow"))
+        .and_then(toml::Value::as_array)
+        .map(|hosts| {
+            hosts
+                .iter()
+                .filter_map(toml::Value::as_str)
+                .map(str::to_string)
+                .collect()
+        })
+        .expect("operation host_allow")
+}
+
+fn host_allowed(host: &str, host_allow: &[String]) -> bool {
+    host_allow.iter().any(|pattern| {
+        pattern == host
+            || pattern
+                .strip_prefix("*.")
+                .is_some_and(|suffix| host.ends_with(&format!(".{suffix}")))
+    })
+}
+
+/// Reddit `list_subreddit_new` API success response.
+fn reddit_list_subreddit_new_response() -> serde_json::Value {
+    json!({
+        "kind": "Listing",
+        "data": {
+            "children": []
+        }
+    })
+}
+
+// ============================================================================
+// Test 1: Default deny -- compliance suite
+// ============================================================================
+
+/// Default deny: invoke without matching capability triggers error.
+/// Token grants "reddit.post" but invoke targets "reddit.list_subreddit_new"
