+use fcp_salesforce::connector::SalesforceConnector;
+use fcp_testkit::MockApiServer;
+use serde_json::json;
+
+struct SalesforceConnectorAdapter {
+    connector: SalesforceConnector,
+    id: ConnectorId,
+    instance_id: InstanceId,
+    verifier: Option<CapabilityVerifier>,
+    introspection: Introspection,
+}
+
+impl SalesforceConnectorAdapter {
+    fn new() -> Self {
+        Self {
+            connector: SalesforceConnector::new(),
+            id: ConnectorId::from_static("salesforce"),
+            instance_id: InstanceId::new(),
+            verifier: None,
+            introspection: Introspection {
+                operations: vec![],
+                events: vec![],
+                resource_types: vec![],
+                auth_caps: None,
+                event_caps: None,
+            },
+        }
+    }
+}
+
+#[fcp_core::async_trait]
+impl FcpConnector for SalesforceConnectorAdapter {
+    fn id(&self) -> &ConnectorId {
+        &self.id
+    }
+
+    async fn configure(&mut self, config: serde_json::Value) -> fcp_core::FcpResult<()> {
+        self.connector.handle_configure(config).await.map(|_| ())
+    }
+
+    async fn handshake(&mut self, req: HandshakeRequest) -> fcp_core::FcpResult<HandshakeResponse> {
+        self.connector
+            .handle_handshake(json!({
+                "session_id": "salesforce-e2e-session",
+            }))
+            .await?;
+
+        self.verifier = Some(CapabilityVerifier::new(
+            req.host_public_key,
+            req.zone.clone(),
+            self.instance_id.clone(),
+        ));
+
+        Ok(HandshakeResponse {
+            status: "accepted".to_string(),
+            capabilities_granted: req
+                .capabilities_requested
+                .iter()
+                .cloned()
+                .map(|capability| CapabilityGrant {
+                    capability,
+                    operation: None,
+                })
+                .collect(),
+            session_id: SessionId::new(),
+            manifest_hash: "sha256:salesforce-e2e".to_string(),
+            nonce: req.nonce,
+            event_caps: None,
+            auth_caps: None,
+            op_catalog_hash: None,
+        })
+    }
+
+    async fn health(&self) -> HealthSnapshot {
+        match self.connector.handle_health().await {
+            Ok(payload) => {
+                let status = payload
+                    .get("status")
+                    .and_then(serde_json::Value::as_str)
+                    .unwrap_or("unknown");
+                match status {
+                    "healthy" => HealthSnapshot::ready(),
+                    "degraded" => HealthSnapshot::degraded("not_handshaken"),
+                    "unconfigured" => HealthSnapshot::degraded("not_configured"),
+                    other => HealthSnapshot::degraded(format!("salesforce_status:{other}")),
+                }
+            }
+            Err(err) => HealthSnapshot::error(err.to_string()),
+        }
+    }
+
+    async fn self_check(&self) -> fcp_core::FcpResult<fcp_core::SelfCheckReport> {
+        let value = self.connector.handle_self_check().await?;
+        serde_json::from_value(value).map_err(|err| FcpError::Internal {
+            message: format!("failed to deserialize Salesforce self_check: {err}"),
+        })
+    }
+
+    fn metrics(&self) -> ConnectorMetrics {
+        ConnectorMetrics::default()
+    }
+
+    async fn shutdown(&mut self, _req: ShutdownRequest) -> fcp_core::FcpResult<()> {
+        self.verifier = None;
+        self.connector.handle_shutdown(json!({})).await.map(|_| ())
+    }
+
+    fn introspect(&self) -> Introspection {
+        self.introspection.clone()
+    }
+
+    async fn invoke(&self, req: InvokeRequest) -> fcp_core::FcpResult<InvokeResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal {
+            message: "Salesforce verifier not initialized; handshake required".into(),
+        })?;
+        let required_capability = required_capability(req.operation.as_str())?;
+        verifier.verify(
+            &req.capability_token,
+            &required_capability,
+            &req.operation,
+            &[],
+        )?;
+
+        let request_id = req.id.clone();
+        let value = self
+            .connector
+            .handle_invoke(json!({
+                "operation_id": req.operation.as_str(),
+                "input": req.input,
+            }))
+            .await?;
+        Ok(InvokeResponse::ok(request_id, value))
+    }
+
+    async fn simulate(&self, req: SimulateRequest) -> fcp_core::FcpResult<SimulateResponse> {
+        let verifier = self.verifier.as_ref().ok_or(FcpError::Internal {
+            message: "Salesforce verifier not initialized; handshake required".into(),
+        })?;
+        let required_capability = required_capability(req.operation.as_str())?;
+        verifier.verify(
+            &req.capability_token,
+            &required_capability,
+            &req.operation,
+            &[],
+        )?;
+
+        let value = self
+            .connector
+            .handle_simulate(json!({
+                "operation_id": req.operation.as_str(),
+                "input": req.input,
+            }))
+            .await?;
+
+        Ok(SimulateResponse {
+            r#type: "simulate_response".to_string(),
+            id: req.id,
+            would_succeed: value
+                .get("allowed")
+                .and_then(serde_json::Value::as_bool)
+                .unwrap_or(false),
+            failure_reason: value
+                .get("reason")
+                .and_then(serde_json::Value::as_str)
+                .filter(|_| {
+                    !value
+                        .get("allowed")
+                        .and_then(serde_json::Value::as_bool)
+                        .unwrap_or(false)
+                })
+                .map(str::to_string),
+            denial_code: None,
+            missing_capabilities: Vec::new(),
+            estimated_cost: None,
+            availability: None,
+            response_metadata: None,
+        })
+    }
+
+    async fn subscribe(&self, _req: SubscribeRequest) -> fcp_core::FcpResult<SubscribeResponse> {
+        Err(FcpError::StreamingNotSupported)
+    }
+
+    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> fcp_core::FcpResult<()> {
+        Ok(())
+    }
+}
+
+fn required_capability(operation: &str) -> fcp_core::FcpResult<CapabilityId> {
+    let capability = match operation {
+        "salesforce.accounts.get" | "salesforce.accounts.list" => "salesforce.accounts.read",
+        "salesforce.contacts.list" => "salesforce.contacts.read",
+        "salesforce.contacts.create" | "salesforce.contacts.delete" => "salesforce.contacts.write",
+        "salesforce.leads.list" => "salesforce.leads.read",
+        "salesforce.leads.convert" => "salesforce.leads.write",
+        "salesforce.opportunities.list" => "salesforce.opportunities.read",
+        "salesforce.opportunities.create" => "salesforce.opportunities.write",
+        "salesforce.cases.list" => "salesforce.cases.read",
+        "salesforce.cases.create" => "salesforce.cases.write",
+        "salesforce.soql.query" => "salesforce.soql.read",
+        "salesforce.reports.get" => "salesforce.reports.read",
+        _ => {
+            return Err(FcpError::InvalidRequest {
+                code: 1002,
+                message: format!("Unknown operation: {operation}"),
+            });
+        }
+    };
+
+    capability
+        .parse::<CapabilityId>()
+        .map_err(|err| FcpError::Internal {
+            message: format!("invalid capability id mapping for {operation}: {err}"),
+        })
+}
+
+fn salesforce_manifest_with_hash() -> String {
+    let raw = include_str!("../../../connectors/salesforce/manifest.toml");
+    let unchecked = ConnectorManifest::parse_str_unchecked(raw).expect("unchecked manifest parse");
+    let computed = unchecked
+        .compute_interface_hash()
+        .expect("compute interface hash");
+    raw.replace(
+        &unchecked.manifest.interface_hash.to_string(),
+        &computed.to_string(),
+    )
+}
+
+fn salesforce_manifest_toml() -> toml::Value {
+    toml::from_str(include_str!(
+        "../../../connectors/salesforce/manifest.toml"
+    ))
+    .expect("Salesforce manifest TOML")
+}
+
+fn salesforce_config(base_url: &str) -> serde_json::Value {
+    json!({
+        "access_token": "salesforce-test-access-token",
+        "base_url": base_url,
+    })
+}
+
+fn handshake_request(host_public_key: [u8; 32], capabilities: &[&str]) -> HandshakeRequest {
+    HandshakeRequest {
+        protocol_version: "2.0".to_string(),
+        zone: ZoneId::work(),
+        zone_dir: None,
+        host_public_key,
+        nonce: [19_u8; 32],
+        capabilities_requested: capabilities
+            .iter()
+            .map(|capability| {
+                capability
+                    .parse::<CapabilityId>()
+                    .expect("capability id parse")
+            })
+            .collect(),
+        host: None,
+        transport_caps: None,
+        requested_instance_id: Some(InstanceId::new()),
+    }
+}
+
+fn build_token(
+    signing_key: &Ed25519SigningKey,
+    capability: &str,
+    operations: &[&str],
+) -> CapabilityToken {
+    let now = Utc::now();
+    let token = CapabilityTokenBuilder::new()
+        .capability_id(capability)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(operations)
+        .issuer("node:test")
+        .validity(now, now + ChronoDuration::hours(1))
+        .sign(signing_key)
+        .expect("capability token sign");
+    CapabilityToken { raw: token }
+}
+
+fn invoke_request(
+    operation: &'static str,
+    input: serde_json::Value,
+    token: CapabilityToken,
+) -> InvokeRequest {
+    InvokeRequest {
+        r#type: "invoke".to_string(),
+        id: RequestId::from("salesforce-e2e"),
+        connector_id: ConnectorId::from_static("salesforce"),
+        operation: OperationId::from_static(operation),
+        zone_id: ZoneId::work(),
+        input,
+        capability_token: token,
+        holder_proof: None,
+        context: None,
+        idempotency_key: None,
+        lease_seq: None,
+        deadline_ms: None,
+        correlation_id: None,
+        provenance: None,
+        approval_tokens: Vec::new(),
+    }
+}
+
+fn operation_network_constraints<'a>(
