+#[test]
+fn segment_manifest_network_guard_allows_and_denies() {
+    let manifest = segment_manifest_toml();
+    let operations = manifest
+        .get("provides")
+        .and_then(toml::Value::as_table)
+        .and_then(|provides| provides.get("operations"))
+        .and_then(toml::Value::as_table)
+        .expect("operations table");
+
+    assert_eq!(
+        operations.len(),
+        3,
+        "Segment manifest should declare 3 operations"
+    );
+
+    let expected_hosts = vec![
+        "api.segmentapis.com".to_string(),
+        "*.segment.io".to_string(),
+        "*.segment.com".to_string(),
+    ];
+
+    for operation_name in operations.keys() {
+        let host_allow = operation_host_allow_list(&manifest, operation_name);
+        assert_eq!(
+            host_allow, expected_hosts,
+            "operation {operation_name} should use exact Segment API host allowlist"
+        );
+
+        assert!(host_allowed("api.segmentapis.com", &host_allow));
+        assert!(host_allowed("cdn.segment.io", &host_allow));
+        assert!(host_allowed("app.segment.com", &host_allow));
+        assert!(!host_allowed("segment.io", &host_allow));
+        assert!(!host_allowed("segment.com", &host_allow));
+        assert!(!host_allowed("example.com", &host_allow));
+        assert!(!host_allowed("127.0.0.1", &host_allow));
+
+        let constraints = operation_network_constraints(&manifest, operation_name);
+        assert_eq!(
+            constraints
+                .get("deny_localhost")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must deny localhost"
+        );
+        assert_eq!(
+            constraints
+                .get("deny_private_ranges")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must deny private ranges"
+        );
+        assert_eq!(
+            constraints
+                .get("require_sni")
+                .and_then(toml::Value::as_bool),
+            Some(true),
+            "operation {operation_name} must require SNI"
+        );
+    }
+}
